"""Google Gemini API client + multi-provider failover."""
import os
import time
import random
import google.generativeai as genai
from google.api_core.exceptions import ResourceExhausted, ServiceUnavailable

genai.configure(api_key=os.environ["GOOGLE_API_KEY"])


# ── Core Gemini client ───────────────────────────────────────────
class GeminiClient:
    def __init__(self, model_name: str = "gemini-2.5-flash", system: str = ""):
        self.model = genai.GenerativeModel(
            model_name=model_name,
            system_instruction=system or None,
        )
        self.model_name = model_name
        self.total_input = 0
        self.total_output = 0

    def chat(self, prompt: str, max_retries: int = 3) -> str:
        for attempt in range(max_retries):
            try:
                response = self.model.generate_content(prompt)
                if hasattr(response, "usage_metadata"):
                    self.total_input  += response.usage_metadata.prompt_token_count or 0
                    self.total_output += response.usage_metadata.candidates_token_count or 0
                return response.text
            except ResourceExhausted:
                if attempt == max_retries - 1:
                    raise
                wait = (2 ** attempt) + random.uniform(0, 1)
                print(f"Rate limited. Retry in {wait:.1f}s")
                time.sleep(wait)
            except ServiceUnavailable:
                if attempt == max_retries - 1:
                    raise
                time.sleep(2 ** attempt)
        raise RuntimeError("All retries exhausted")

    def stream(self, prompt: str) -> str:
        response = self.model.generate_content(prompt, stream=True)
        full = ""
        for chunk in response:
            if chunk.text:
                print(chunk.text, end="", flush=True)
                full += chunk.text
        print()
        return full

    def cost_report(self) -> str:
        PRICING = {
            "gemini-2.5-pro":     {"input": 1.25,  "output": 10.00},
            "gemini-2.5-flash":   {"input": 0.075, "output": 0.30},
        }
        p = PRICING.get(self.model_name, {"input": 1.25, "output": 10.00})
        cost = (self.total_input / 1_000_000) * p["input"] + (self.total_output / 1_000_000) * p["output"]
        return f"In: {self.total_input:,} | Out: {self.total_output:,} | ${cost:.6f}"


# ── Multi-provider failover client ────────────────────────────────
class MultiProviderClient:
    """Tries providers in order, falls back on failure."""

    def __init__(self, system: str = ""):
        self.system = system
        self.providers = ["openai", "anthropic", "google"]

    def _call_openai(self, prompt: str) -> str:
        from openai import OpenAI
        c = OpenAI()
        r = c.chat.completions.create(
            model="gpt-4o",
            messages=[
                {"role": "system",  "content": self.system},
                {"role": "user",    "content": prompt}
            ],
            max_tokens=1024,
        )
        return r.choices[0].message.content

    def _call_anthropic(self, prompt: str) -> str:
        import anthropic
        c = anthropic.Anthropic()
        r = c.messages.create(
            model="claude-sonnet-4-6",
            max_tokens=1024,
            system=self.system,
            messages=[{"role": "user", "content": prompt}],
        )
        return r.content[0].text

    def _call_google(self, prompt: str) -> str:
        g = GeminiClient(system=self.system)
        return g.chat(prompt)

    def complete(self, prompt: str) -> tuple[str, str]:
        """Returns (response_text, provider_used)."""
        callers = {
            "openai":    self._call_openai,
            "anthropic": self._call_anthropic,
            "google":    self._call_google,
        }
        for provider in self.providers:
            try:
                result = callers[provider](prompt)
                return result, provider
            except Exception as e:
                print(f"[{provider}] failed: {e}. Trying next provider...")
        raise RuntimeError("All providers failed")


if __name__ == "__main__":
    # Single Gemini call
    client = GeminiClient(system="Answer in one sentence.")
    reply = client.chat("What is the capital of Japan?")
    print(f"Gemini: {reply}")
    print(client.cost_report())

    # Multi-provider failover demo (shows the pattern)
    multi = MultiProviderClient(system="You are a helpful assistant.")
    print("\nMulti-provider client initialized with fallback: openai → anthropic → google")

