import os
import json

class CodebaseSummarizer:
    def __init__(self):
        genai.configure(api_key=os.environ['GOOGLE_API_KEY'])
        self.model = genai.GenerativeModel('gemini-2.5-pro')
        self.SYSTEM = 'You are a senior software architect. Analyze codebases precisely.'

    def collect_files(self, directory: str) -> str:
        parts = []
        for root, _, files in os.walk(directory):
            for fname in sorted(files):
                if fname.endswith('.py'):
                    path = os.path.join(root, fname)
                    try:
                        content = open(path).read()
                        parts.append(f'# === {path} ===\n{content}\n')
                    except Exception:
                        pass
        return '\n'.join(parts)

    def summarize(self, directory: str) -> dict:
        code = self.collect_files(directory)
        token_estimate = len(code) // 4
        if token_estimate > 800_000:
            raise ValueError(f'Codebase too large: ~{token_estimate:,} tokens (max 800K)')

        prompt = f'''Analyze this Python codebase and return JSON with keys:
{{"architecture": "summary", "key_components": [{{"name": "", "purpose": ""}}], "patterns": [""], "issues": [""]}}

Codebase:\n{code}'''
        response = self.model.generate_content(prompt)
        try:
            return json.loads(response.text)
        except json.JSONDecodeError:
            return {'raw': response.text, 'token_estimate': token_estimate}

