def with_fallback(prompt: str, system: str, providers: list[str]) -> tuple[str, str]:
    errors = []
    for provider in providers:
        try:
            if provider == 'openai':
                from openai import OpenAI
                c = OpenAI()
                r = c.chat.completions.create(
                    model='gpt-4o',
                    messages=[{'role': 'system', 'content': system}, {'role': 'user', 'content': prompt}],
                    max_tokens=1024
                )
                return r.choices[0].message.content, provider
            elif provider == 'google':
                import google.generativeai as genai
                m = genai.GenerativeModel('gemini-2.5-flash', system_instruction=system)
                return m.generate_content(prompt).text, provider
        except Exception as e:
            errors.append(f'{provider}: {e}')
    raise RuntimeError(f'All providers failed: {errors}')
